  default     = ""
  validation {
    condition     = var.sap_subscription_id == "" || can(regex("^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$", var.sap_subscription_id))
    error_message = "sap_subscription_id must be a valid UUID or empty string."
  }
}

variable "sap_dns_zone_name" {
  description = "Private DNS zone name for SAP hostname resolution"
  type        = string
  default     = "sap.internal"
}

variable "sap_dns_records" {
  description = "Map of SAP hostname to IP address for DNS A records"
  type        = map(string)
  default     = {}
}

variable "sap_dns_record_ttl" {
  description = "TTL in seconds for SAP DNS A records"
  type        = number
  default     = 300
  validation {
    condition     = var.sap_dns_record_ttl >= 60 && var.sap_dns_record_ttl <= 86400
    error_message = "DNS record TTL must be between 60 and 86400 seconds."
  }
}

variable "sap_allow_gateway_transit" {
  description = "Allow gateway transit on SAP → AKS peering (set true if SAP VNet has a VPN/ExpressRoute gateway)"
  type        = bool
  default     = false
}

variable "sap_use_remote_gateways" {
  description = "Use remote gateways from SAP VNet on AKS → SAP peering"
  type        = bool
  default     = false
}

variable "tags" {
  description = "Tags to apply to all resources"
  type        = map(string)
  default     = {}
}

# --------------------------------------------------------------------------
# AKS Configuration (Story 1.2)
# --------------------------------------------------------------------------

variable "kubernetes_version" {
  description = "Kubernetes version for the AKS cluster (1.32 recommended, LTS until July 2028)"
  type        = string
  default     = "1.32"
  validation {
    condition     = can(regex("^[0-9]+\\.[0-9]+(\\.[0-9]+)?$", var.kubernetes_version))
    error_message = "kubernetes_version must be a valid semver format (e.g., '1.32' or '1.32.1')."
  }
}

variable "aks_sku_tier" {
  description = "AKS SKU tier — Free (DEV), Standard (PRD, SLA-backed)"
  type        = string
  default     = "Free"
  validation {
    condition     = contains(["Free", "Standard", "Premium"], var.aks_sku_tier)
    error_message = "AKS SKU tier must be 'Free', 'Standard', or 'Premium'."
  }
}

variable "system_node_pool_vm_size" {
  description = "VM size for the AKS system node pool"
  type        = string
  default     = "Standard_D4s_v3"
}

variable "system_node_pool_node_count" {
  description = "Number of nodes in the system node pool (min 3 for HA across 3 AZs)"
  type        = number
  default     = 3
}

variable "user_node_pool_vm_size" {
  description = "VM size for the user (workload) node pool — Python CronJobs"
  type        = string
  default     = "Standard_D4s_v5"
}

variable "user_node_pool_min_count" {
  description = "Minimum number of nodes for user pool autoscaling (NFR15)"
  type        = number
  default     = 3
}

variable "user_node_pool_max_count" {
  description = "Maximum number of nodes for user pool autoscaling (NFR15)"
  type        = number
  default     = 10
}

variable "acr_name" {
  description = "Name for the Azure Container Registry (no hyphens, globally unique)"
  type        = string
  validation {
    condition     = can(regex("^[a-zA-Z0-9]{5,50}$", var.acr_name))
    error_message = "ACR name must be 5-50 alphanumeric characters only (no hyphens)."
  }
}

variable "acr_sku" {
  description = "SKU for Azure Container Registry — Standard (DEV), Premium (PRD)"
  type        = string
  default     = "Premium"
}

variable "aks_admin_group_object_ids" {
  description = "List of Azure AD group object IDs for AKS cluster admin access"
  type        = list(string)
  default     = []
}

variable "service_cidr" {
  description = "Kubernetes service CIDR — must not overlap with VNet address space (default: 172.16.0.0/16)"
  type        = string
  default     = "172.16.0.0/16"
}

variable "dns_service_ip" {
  description = "IP address for the Kubernetes DNS service (must be within service_cidr)"
  type        = string
  default     = "172.16.0.10"
}

# --------------------------------------------------------------------------
# Namespace Configuration (Story 1.3)
# --------------------------------------------------------------------------

variable "namespaces" {
  description = "Map of namespace names to configuration overrides. Keys are business area names (e.g., 'logistica')."
  type = map(object({
    cpu_request      = optional(string, "2")
    cpu_limit        = optional(string, "4")
    memory_request   = optional(string, "2Gi")
    memory_limit     = optional(string, "4Gi")
    max_pods         = optional(number, 20)
    sap_egress_cidrs = optional(list(string), [])
    sap_egress_ports = optional(list(number), [443, 3300])
  }))
  default = {
    logistica = {}
  }
}

variable "ad_group_dev_object_id" {
  description = "Azure AD group object ID for GRP-PYTHON-DEV (developer role, own namespace only)"
  type        = string
  default     = ""
  validation {
    condition     = var.ad_group_dev_object_id == "" || can(regex("^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$", var.ad_group_dev_object_id))
    error_message = "ad_group_dev_object_id must be a valid UUID or empty string."
  }
}

variable "ad_group_review_object_id" {
  description = "Azure AD group object ID for GRP-PYTHON-REVIEW (read-only across all namespaces)"
  type        = string
  default     = ""
  validation {
    condition     = var.ad_group_review_object_id == "" || can(regex("^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$", var.ad_group_review_object_id))
    error_message = "ad_group_review_object_id must be a valid UUID or empty string."
  }
}

variable "ad_group_ops_object_id" {
  description = "Azure AD group object ID for GRP-PYTHON-OPS (view, logs, exec across all namespaces)"
  type        = string
  default     = ""
  validation {
    condition     = var.ad_group_ops_object_id == "" || can(regex("^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$", var.ad_group_ops_object_id))
    error_message = "ad_group_ops_object_id must be a valid UUID or empty string."
  }
}

variable "ad_group_admin_object_id" {
  description = "Azure AD group object ID for GRP-PYTHON-ADMIN (full cluster admin)"
  type        = string
  default     = ""
  validation {
    condition     = var.ad_group_admin_object_id == "" || can(regex("^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$", var.ad_group_admin_object_id))
    error_message = "ad_group_admin_object_id must be a valid UUID or empty string."
  }
}

# --------------------------------------------------------------------------
# Security / Key Vault Configuration (Story 3.1)
# --------------------------------------------------------------------------

variable "key_vault_sku" {
  description = "SKU for Azure Key Vault (standard or premium)"
  type        = string
  default     = "standard"
  validation {
    condition     = contains(["standard", "premium"], var.key_vault_sku)
    error_message = "Key Vault SKU must be 'standard' or 'premium'."
  }
}

variable "key_vault_soft_delete_retention_days" {
  description = "Number of days to retain soft-deleted Key Vault (7-90)"
  type        = number
  default     = 90
  validation {
    condition     = var.key_vault_soft_delete_retention_days >= 7 && var.key_vault_soft_delete_retention_days <= 90
    error_message = "Soft delete retention must be between 7 and 90 days."
  }
}

variable "audit_log_retention_days" {
  description = "Number of days to retain Key Vault audit logs (minimum 90 per NFR3)"
  type        = number
  default     = 90
  validation {
    condition     = var.audit_log_retention_days >= 90
    error_message = "Audit log retention must be at least 90 days per NFR3."
  }
}

variable "default_sap_egress_cidrs" {
  description = "Default SAP CIDR blocks for namespace egress network policies"
  type        = list(string)
  default     = []
}

variable "default_sap_egress_ports" {
  description = "Default SAP egress ports (TCP) for network policies"
  type        = list(number)
  default     = [443, 3300]
}

# --------------------------------------------------------------------------
# CI / Azure DevOps Configuration (Story 4.1)
# --------------------------------------------------------------------------

variable "azuredevops_org_url" {
  description = "Azure DevOps organization URL (e.g., https://dev.azure.com/hypera)"
  type        = string
  default     = ""
  validation {
    condition     = var.azuredevops_org_url == "" || can(regex("^https://dev\\.azure\\.com/.+$", var.azuredevops_org_url))
    error_message = "Organization URL must be in the format https://dev.azure.com/<org> or empty string."
  }
}

variable "azuredevops_project_name" {
  description = "Name of the Azure DevOps project for CI/CD"
  type        = string
  default     = "hypera-aks-python-infra"
}

variable "azuredevops_repository_name" {
  description = "Name of the Git repository in Azure DevOps"
  type        = string
  default     = "hypera-aks-python-infra"
}

variable "min_reviewer_count" {
  description = "Minimum number of PR reviewers required before merge (AC #3)"
  type        = number
  default     = 1
  validation {
    condition     = var.min_reviewer_count >= 1 && var.min_reviewer_count <= 10
    error_message = "Minimum reviewer count must be between 1 and 10."
  }
}

# --------------------------------------------------------------------------
# CI Pipeline / ACR Service Connection (Story 4.3)
# --------------------------------------------------------------------------

variable "azure_subscription_name" {
  description = "Azure subscription name for ACR service connection display"
  type        = string
  default     = ""
}

variable "azure_tenant_id" {
  description = "Azure AD tenant ID for ACR service connection"
  type        = string
  default     = ""
}

# --------------------------------------------------------------------------
# ArgoCD / GitOps Configuration (Story 4.4)
# --------------------------------------------------------------------------

variable "argocd_namespace" {
  description = "Kubernetes namespace for ArgoCD installation"
  type        = string
  default     = "argocd"
}

variable "argocd_chart_version" {
  description = "ArgoCD Helm chart version (argoproj.github.io/argo-helm)"
  type        = string
  default     = "9.4.2"
  validation {
    condition     = can(regex("^[0-9]+\\.[0-9]+\\.[0-9]+$", var.argocd_chart_version))
    error_message = "ArgoCD chart version must be a valid semver (e.g., '9.4.2')."
  }
}

variable "argocd_helm_timeout" {
  description = "Timeout in seconds for the ArgoCD Helm release"
  type        = number
  default     = 600
  validation {
    condition     = var.argocd_helm_timeout >= 120 && var.argocd_helm_timeout <= 1800
    error_message = "Helm timeout must be between 120 and 1800 seconds."
  }
}

variable "argocd_git_repo_url" {
  description = "Git repository URL for ArgoCD to watch (Azure DevOps repo)"
  type        = string
  default     = "https://dev.azure.com/hypera/python-governance/_git/python-governance"
  validation {
    condition     = can(regex("^https://", var.argocd_git_repo_url))
    error_message = "Git repository URL must start with https://."
  }
}

variable "argocd_git_target_revision" {
  description = "Git branch or revision for ArgoCD to track"
  type        = string
  default     = "HEAD"
}

variable "argocd_reconciliation_timeout_seconds" {
  description = "ArgoCD reconciliation timeout — drift revert window (NFR12: <= 180s for 3-min revert)"
  type        = number
  default     = 180
  validation {
    condition     = var.argocd_reconciliation_timeout_seconds >= 30 && var.argocd_reconciliation_timeout_seconds <= 600
    error_message = "Reconciliation timeout must be between 30 and 600 seconds."
  }
}

variable "argocd_prd_sync_window_enabled" {
  description = "Enable sync window restrictions for PRD (manual approval gate per Decision 4.3)"
  type        = bool
  default     = true
}

variable "argocd_prd_sync_window_schedule" {
  description = "Cron schedule for the PRD manual sync window deny rule"
  type        = string
  default     = "* * * * *"
}

